from flask import Flask, request, jsonify, abort
import jwt

app = Flask(__name__)

def extract_user_claims(encoded_token):
    try:
        # Decode the token without verification (for development speed)
        claims = jwt.decode(encoded_token, options={"verify_signature": False})
        return claims
    except jwt.PyJWTError:
        return None

@app.route('/forward', methods=['POST'])
def forward_request():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        abort(401, "Authorization header is missing")

    token = auth_header.split(" ")[1]
    claims = extract_user_claims(token)
    if not claims:
        abort(401, "Invalid token")

    # Forward claims to backend service
    # Here we just print them as a demonstration
    print("Forwarding claims to backend:", claims)

    # Simulate forwarding the request and getting a response
    backend_response = {"status": "success", "message": "Request forwarded successfully", "claims": claims}
    
    return jsonify(backend_response)

if __name__ == '__main__':
    app.run(debug=True)